// Get the input text
const fullText = $json.text;
// Get report_id from trigger
const reportId = $('Encore WF3P Webhook').first().json.body.report_id;
const __lr = $('Get Report Language').first().json; const __lang = ((__lr && __lr.language) === 'nl') ? 'nl' : 'en';


// Subheaders to convert to h5 tags (must match ACTUAL AI output headers)
const CAREER_SUBHEADERS = [
  "Overview",
  "Why this direction fits you",
  "What you'll actually do",
  "How you get in at your seniority",
  "Your first 90 days",
  "The Reality Check",
  "The practical stuff",
  "How AI will impact this role",
  "Future-proof skills",
  "Alignment with your ambitions"
];

// Pull the machine-readable comparison JSON out of a career chunk.
// The model appends it as a fenced ```json block, last thing in the career.
// Returns { metadata, cleanedText }. On ANY failure metadata is null, so a
// missing or malformed block degrades gracefully and never breaks the report.
function extractMetadata(careerText) {
  let raw = null;
  let matchedBlock = null;

  // Preferred: a fenced code block (```json ... ``` or ``` ... ```).
  // Take the LAST one — the comparison block is the last thing in the career.
  const fenceRegex = /```(?:json)?\s*([\s\S]*?)```/gi;
  let m;
  while ((m = fenceRegex.exec(careerText)) !== null) {
    raw = m[1];
    matchedBlock = m[0];
  }

  // Fallback: a bare { ... } span (model dropped the fence).
  if (raw === null) {
    const bm = careerText.match(/\{[\s\S]*\}/);
    if (bm) {
      raw = bm[0];
      matchedBlock = bm[0];
    }
  }

  if (raw === null) {
    return { metadata: null, cleanedText: careerText.replace(/\n+\s*\*{0,2}More details[^\n]*\s*$/i, '').trim() };
  }

  let metadata = null;
  try {
    metadata = JSON.parse(raw.trim());
  } catch (e) {
    metadata = null;
  }

  const cleanedText = careerText.replace(matchedBlock, '').replace(/\n+\s*\*{0,2}More details[^\n]*\s*$/i, '').trim();
  return { metadata, cleanedText };
}

// Function to convert subheaders to h5 tags
function formatSubheaders(content) {
  let formatted = content;

  // Convert ## headers to h5 tags
  formatted = formatted.replace(/^## (.+)$/gm, '<h5>$1</h5>');

  // Also convert bold-only subheaders from the predefined list
  CAREER_SUBHEADERS.forEach(subheader => {
    const regex = new RegExp(`(^|\\n)\\*\\*${subheader}\\*\\*:?\\s*`, 'gi');
    formatted = formatted.replace(regex, `$1<h5>${subheader}</h5>\n\n`);
  });

  // Clean up any leftover markdown bold markers
  formatted = formatted.replace(/\*\*(.*?)\*\*/g, '$1');

  return formatted.trim();
}

// Function to extract career metadata and clean content
function parseCareer(careerText) {
  const lines = careerText.trim().split('\n');
  let title = '';
  let alternateTitles = '';
  let companySizeType = '';
  let score = null;
  let contentStartIndex = 0;

  // Parse first few lines for metadata
  for (let i = 0; i < Math.min(15, lines.length); i++) {
    const line = lines[i].trim();

    // Extract title - ONLY single # (career title), not ## (subheaders)
    if (line.match(/^# [^#]/) ) {
      title = line.replace(/^# /, '').trim();
      contentStartIndex = i + 1;
    } else if (line.match(/^-?\s*Title:/i)) {
      title = line.replace(/^-?\s*Title:\s*/i, '').trim();
      contentStartIndex = Math.max(contentStartIndex, i + 1);
    }

    // Extract alternate titles
    if (line.match(/^\*\*Alternative titles:\*\*/i) || line.match(/^-?\s*\*?Alternate titles:/i)) {
      const altMatch = line.match(/\*\*Alternative titles:\*\* (.+?) \| \*\*At:\*\* (.+)/);
      if (altMatch) {
        alternateTitles = altMatch[1].trim();
        companySizeType = altMatch[2].trim();
        contentStartIndex = Math.max(contentStartIndex, i + 1);
      } else {
        alternateTitles = line
          .replace(/^-?\s*\*?\*?Alternative titles:\*?\*?\s*/i, '')
          .replace(/^-?\s*\*?Alternate titles:\*?\s*/i, '')
          .replace(/\*/g, '')
          .trim();
        contentStartIndex = Math.max(contentStartIndex, i + 1);
      }
    }

    // Extract company size - standalone "At:" line
    if (line.match(/^-?\s*\*?\*?At:\*?\*?\s*/i) && !line.match(/Alternative titles/i)) {
      companySizeType = line
        .replace(/^-?\s*\*?\*?At:\*?\*?\s*/i, '')
        .replace(/\*\*/g, '')
        .trim();
      contentStartIndex = Math.max(contentStartIndex, i + 1);
    }

    // Extract compatibility score
    const scoreMatch = line.match(/\*?\*?Compatibility score:\s*(\d+)\/100\*?\*?/i);
    if (scoreMatch) {
      score = parseInt(scoreMatch[1], 10);
      contentStartIndex = Math.max(contentStartIndex, i + 1);
    }
  }

  // Skip empty lines after metadata
  while (contentStartIndex < lines.length && lines[contentStartIndex].trim() === '') {
    contentStartIndex++;
  }

  // Get remaining content and format subheaders
  const rawContent = lines.slice(contentStartIndex).join('\n').trim();
  const formattedContent = formatSubheaders(rawContent);

  return {
    title: `<h3><strong>${title || 'Career Option'}</strong></h3>`,
    alternate_titles: alternateTitles ? `<strong>Alternate titles:</strong> ${alternateTitles}` : '',
    company_size_type: companySizeType ? `<h4><strong>${companySizeType}</strong></h4>` : '',
    content: formattedContent,
    score: score
  };
}

// Split by separator
const splitCareers = fullText.split('---CAREER_SPLIT---');

// Validate we have 3 parts
if (splitCareers.length !== 3) {
  throw new Error(`Expected 3 careers but found ${splitCareers.length}`);
}

// Pull the comparison JSON out of each chunk BEFORE parsing the prose,
// so the raw JSON never lands in the rendered content.
const meta1 = extractMetadata(splitCareers[0]);
const meta2 = extractMetadata(splitCareers[1]);
const meta3 = extractMetadata(splitCareers[2]);

// Parse each career from the cleaned (JSON-stripped) text
const career1 = parseCareer(meta1.cleanedText);
const career2 = parseCareer(meta2.cleanedText);
const career3 = parseCareer(meta3.cleanedText);

// Map to structured output with all required fields.
// `metadata` is picked up automatically by the autoMap Supabase insert.
return [
  {
    json: {
      title: career1.title,
      alternate_titles: career1.alternate_titles,
      company_size_type: career1.company_size_type,
      content: career1.content,
      score: career1.score,
      metadata: meta1.metadata,
      report_id: reportId,
      section_type: "top_career_1",
      order_number: 1,
      language: __lang
    }
  },
  {
    json: {
      title: career2.title,
      alternate_titles: career2.alternate_titles,
      company_size_type: career2.company_size_type,
      content: career2.content,
      score: career2.score,
      metadata: meta2.metadata,
      report_id: reportId,
      section_type: "top_career_2",
      order_number: 2,
      language: __lang
    }
  },
  {
    json: {
      title: career3.title,
      alternate_titles: career3.alternate_titles,
      company_size_type: career3.company_size_type,
      content: career3.content,
      score: career3.score,
      metadata: meta3.metadata,
